+
+        let events = gr.process(
+            &mouse_up(30, 20, MouseButton::Left),
+            t + Duration::from_millis(300),
+        );
+        assert!(matches!(
+            events[0],
+            SemanticEvent::DragEnd {
+                start: Position { x: 20, y: 20 },
+                end: Position { x: 30, y: 20 },
+            }
+        ));
+    }
